const STALE_HOURS = 72;
const now = Math.floor(Date.now() / 1000);
const rows = ($input.item.json.stdout || '').trim().split('\n').map(l => l.split(' '));
const issues = [];
for (const [name, mtime] of rows) {
  if (mtime === 'UNBUILT') { issues.push(`• ${name} has no dist/`); continue; }
  const ageHours = (now - parseInt(mtime, 10)) / 3600;
  if (ageHours > STALE_HOURS) issues.push(`• ${name} dist/ is ${ageHours.toFixed(1)}h old`);
}
if (issues.length === 0) return [];
return [{ json: {
  priority: 'P0',
  source: 'cluster-smoke-fs',
  message: `${issues.length} cluster site${issues.length>1?'s':''} unbuilt or stale:\n${issues.join('\n')}`,
  url: ($env.EMPIRE_CONSOLE_BASE_URL || 'http://localhost:4327') + '/check/cluster'
}}];
